// Get the raw string
const raw = $input.first().json.output;

// Helper: remove ```json ... ``` fences if present
function stripFences(s) {
  if (typeof s !== 'string') return s;
  return s.trim()
    .replace(/^```[a-zA-Z]*\s*/i, '')   // leading ``` or ```json
    .replace(/```[\s]*$/i, '')          // trailing ```
    .trim();
}

// Helper: robust JSON parse (handles double-encoded JSON too)
function robustParse(s) {
  if (typeof s !== 'string') return s;
  let t = stripFences(s);
  try { return JSON.parse(t); } catch (e1) {}
  // Sometimes the JSON is stringified twice
  try { return JSON.parse(JSON.parse(t)); } catch (e2) {}
  // Fallback: try to extract the first {...} block
  const m = t.match(/\{[\s\S]*\}$/);
  if (m) { return JSON.parse(m[0]); }
  throw new Error('Could not parse JSON from `output` – check the upstream node.');
}

const parsed = robustParse(raw);
return [{ json: parsed }];

// Create comprehensive audit log entry
const items = $input.all();
const firstItem = items[0];

// Extract file information from binary data
const binaryKeys = Object.keys(firstItem.binary || {});
const firstBinaryKey = binaryKeys[0];
const binaryData = firstBinaryKey ? firstItem.binary[firstBinaryKey] : null;

// Extract request headers and body
const headers = firstItem.json.headers || {};
const body = firstItem.json.body || {};

// Get GDPR configuration from Workflow Configuration node
const config = firstItem.json;
const dataRetentionDays = config.dataRetentionDays || 30;

// Create audit log entry
const auditLog = {
  execution_id: $execution.id,
  workflow_id: $workflow.id,
  user_id: body.user_id || body.userId || null,
  timestamp: new Date().toISOString(),
  file_name: binaryData?.fileName || body.file_name || body.fileName || 'unknown',
  file_size: binaryData?.fileSize || body.file_size || body.fileSize || 0,
  mime_type: binaryData?.mimeType || body.mime_type || body.mimeType || 'unknown',
  consent_given: body.consent_given === true || body.consentGiven === true || body.consent === true,
  ip_address: headers['x-forwarded-for'] || headers['x-real-ip'] || headers['cf-connecting-ip'] || 'unknown',
  processing_stage: 'initiated',
  legal_basis: 'consent',
  processing_purpose: config.consentPurpose || 'Document processing and data extraction',
  data_controller: config.gdprDataController || 'Organization Name',
  data_retention_notice: `Data will be automatically deleted after ${dataRetentionDays} days in compliance with GDPR data minimization principles`
};

return [{
  json: {
    ...firstItem.json,
    audit_log: auditLog
  },
  binary: firstItem.binary
}];

const crypto = require('crypto');

// Helper function to create SHA-256 hash
function hashValue(value) {
  return crypto.createHash('sha256').update(value).digest('hex');
}

// Helper function to generate unique ID
function generateId() {
  return `mask_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

// Helper function to encrypt data using AES-256-GCM
function encryptValue(value, keyId) {
  // Get encryption key from environment variable or use a secure default
  // In production, this should come from a secure key management system
  const encryptionKey = process.env.ENCRYPTION_KEY || 'default-32-byte-encryption-key!';

  // Ensure key is 32 bytes for AES-256
  const key = crypto.createHash('sha256').update(encryptionKey).digest();

  // Generate a random initialization vector
  const iv = crypto.randomBytes(16);

  // Create cipher
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);

  // Encrypt the value
  let encrypted = cipher.update(value, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  // Get authentication tag
  const authTag = cipher.getAuthTag();

  // Return encrypted data with IV and auth tag for decryption
  return {
    encrypted: encrypted,
    iv: iv.toString('hex'),
    authTag: authTag.toString('hex'),
    keyId: keyId
  };
}

// Helper function to categorize PII types
function categorizePII(type) {
  const categories = {
    personal_identifiers: ['socialSecurityNumber', 'passportNumber', 'idCardNumber', 'taxId', 'driversLicense', 'healthInsurance', 'personName', 'dateOfBirth'],
    financial_data: ['iban', 'creditCard', 'vatId'],
    contact_info: ['email', 'phone', 'fax'],
    location_data: ['postalCode', 'streetAddress', 'ipv4', 'ipv6']
  };

  for (const [category, types] of Object.entries(categories)) {
    if (types.includes(type)) {
      return category;
    }
  }

  return 'other';
}

// Comprehensive GDPR-compliant masking patterns
const patterns = {
  // German company legal forms - using word boundaries to match only standalone suffixes
  companyLegalForm: /\b(GmbH|AG|KG|OHG|GbR|UG|e\.V\.|eV|mbH|Co\. KG|GmbH & Co\. KG)\b/gi,

  // German person names (first and last name combinations)
  personName: /\b[A-ZÄÖÜ][a-zäöüß]+\s+[A-ZÄÖÜ][a-zäöüß]+\b/g,

  // Email addresses
  email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,

  // German phone numbers (enhanced to include mobile formats)
  // Matches: +49 xxx xxxx, 0xxx xxxx, mobile 015x/016x/017x
  phone: /\b(?:\+49[\s.-]?|0)(?:1[5-7]\d|[2-9]\d{1,4})[\s.-]?\d{3,}[\s.-]?\d{3,}\b/g,

  // Fax numbers (similar pattern to phone)
  fax: /\b(?:Fax|FAX|fax)[:\s]*(?:\+49[\s.-]?|0)[1-9]\d{1,4}[\s.-]?\d{3,}[\s.-]?\d{3,}\b/gi,

  // German postal codes (5 digits)
  postalCode: /\b\d{5}\b/g,

  // German tax ID (Steuernummer) - various formats
  // Format: 12/345/67890 or 123/456/7890 or similar
  taxId: /\b\d{2,3}\/\d{3}\/\d{4,5}\b/g,

  // German VAT ID (Umsatzsteuer-Identifikationsnummer)
  // Format: DE + 9 digits
  vatId: /\bDE\d{9}\b/gi,

  // IBAN (International Bank Account Number)
  // Format: 2 letters + 2 digits + up to 30 alphanumeric characters
  iban: /\b[A-Z]{2}\d{2}[A-Z0-9]{1,30}\b/gi,

  // German social security number (Sozialversicherungsnummer)
  // Format: 12 digits with specific structure
  socialSecurityNumber: /\b\d{2}\s?\d{6}\s?[A-Z]\s?\d{3}\b/gi,

  // German passport number
  // Format: C + 8 digits or various other formats
  passportNumber: /\b[CFGHJKLMNPRTVWXYZ]\d{8}\b/gi,

  // German ID card number (Personalausweisnummer)
  // Format: 9 alphanumeric characters or 10 digits
  idCardNumber: /\b[A-Z0-9]{9,10}(?=\s|$)/g,

  // German driver's license number
  // Format: 11 alphanumeric characters
  driversLicense: /\b[A-Z0-9]{11}\b/g,

  // German health insurance number
  // Format: Letter + 9 digits
  healthInsurance: /\b[A-Z]\d{9}\b/gi,

  // Credit card numbers
  // Format: 4 groups of 4 digits with optional spaces or hyphens
  creditCard: /\b(?:\d{4}[\s-]?){3}\d{4}\b/g,

  // IPv4 addresses
  ipv4: /\b(?:(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\.){3}(?:25[0-5]|2[0-4]\d|[01]?\d\d?)\b/g,

  // IPv6 addresses (simplified pattern)
  ipv6: /\b(?:[0-9a-fA-F]{1,4}:){7}[0-9a-fA-F]{1,4}\b|\b(?:[0-9a-fA-F]{1,4}:){1,7}:\b|\b::(?:[0-9a-fA-F]{1,4}:){0,6}[0-9a-fA-F]{1,4}\b/g,

  // German street addresses
  // Matches: Straße/Str./Weg/Platz/Allee + house number
  streetAddress: /\b[A-ZÄÖÜ][a-zäöüß]+(?:straße|str\.|weg|platz|allee|gasse|ring|damm|ufer)\s+\d+[a-z]?\b/gi,

  // Date of birth patterns (DD.MM.YYYY or DD/MM/YYYY)
  dateOfBirth: /\b(?:0[1-9]|[12]\d|3[01])[\.\/-](?:0[1-9]|1[0-2])[\.\/-](?:19|20)\d{2}\b/g,

  // Nosta company name (case-insensitive)
  nosta: /\bNosta\b/gi
};

// Masking functions for each PII type
const maskingFunctions = {
  companyLegalForm: (value) => '[FILTERED_LEGAL_FORM]',
  personName: (value) => '[MASKED_NAME]',
  email: (value) => {
    const [local, domain] = value.split('@');
    const maskedLocal = local.length > 2 ? local[0] + '***' + local[local.length - 1] : '***';
    return `${maskedLocal}@${domain}`;
  },
  phone: (value) => value.replace(/.(?=.{4})/g, '*'),
  fax: (value) => {
    const match = value.match(/(Fax|FAX|fax)[:\s]*(.*)/i);
    if (match) {
      const label = match[1];
      const number = match[2];
      return `${label}: ${number.replace(/.(?=.{4})/g, '*')}`;
    }
    return value.replace(/.(?=.{4})/g, '*');
  },
  postalCode: (value) => '[MASKED_POSTAL_CODE]',
  taxId: (value) => '[MASKED_TAX_ID]',
  vatId: (value) => '[MASKED_VAT_ID]',
  iban: (value) => '[MASKED_IBAN]',
  socialSecurityNumber: (value) => '[MASKED_SSN]',
  passportNumber: (value) => '[MASKED_PASSPORT]',
  idCardNumber: (value) => '[MASKED_ID_CARD]',
  driversLicense: (value) => '[MASKED_LICENSE]',
  healthInsurance: (value) => '[MASKED_HEALTH_INS]',
  creditCard: (value) => '[MASKED_CREDIT_CARD]',
  ipv4: (value) => '[MASKED_IP]',
  ipv6: (value) => '[MASKED_IP]',
  streetAddress: (value) => '[MASKED_ADDRESS]',
  dateOfBirth: (value) => '[MASKED_DOB]',
  nosta: (value) => '[FILTERED_COMPANY]'
};

// Process all items
return items.map(item => {
  let text = item.json.text || '';
  const maskingMap = [];
  let maskedCount = 0;
  const encryptionKeyId = `key_${Date.now()}`;

  // Track already masked positions to avoid double-masking
  const maskedPositions = new Set();

  // Track PII categories for GDPR compliance
  const piiCategoriesDetected = new Set();

  // Process each PII type in priority order (more specific patterns first)
  const processingOrder = [
    'iban', 'creditCard', 'vatId', 'taxId', 'socialSecurityNumber', 'passportNumber',
    'idCardNumber', 'driversLicense', 'healthInsurance', 'email', 'ipv6', 'ipv4', 
    'streetAddress', 'dateOfBirth', 'personName', 'phone', 'fax', 'postalCode', 
    'companyLegalForm', 'nosta'
  ];

  for (const type of processingOrder) {
    const pattern = patterns[type];
    if (!pattern) continue;

    const matches = [...text.matchAll(pattern)];

    matches.forEach(match => {
      const originalValue = match[0];
      const position = match.index;

      // Skip if this position was already masked
      if (maskedPositions.has(position)) return;

      // Additional validation for certain types to reduce false positives
      if (type === 'postalCode') {
        // Skip if postal code is part of a larger number
        const before = text[position - 1];
        const after = text[position + originalValue.length];
        if ((before && /\d/.test(before)) || (after && /\d/.test(after))) {
          return;
        }
      }

      if (type === 'idCardNumber' || type === 'driversLicense') {
        // Skip common false positives (e.g., order numbers, article numbers)
        if (text.substring(Math.max(0, position - 20), position).toLowerCase().includes('artikel') ||
            text.substring(Math.max(0, position - 20), position).toLowerCase().includes('order') ||
            text.substring(Math.max(0, position - 20), position).toLowerCase().includes('pos')) {
          return;
        }
      }

      if (type === 'personName') {
        // Skip if it looks like a company name or common false positives
        const context = text.substring(Math.max(0, position - 30), Math.min(text.length, position + originalValue.length + 30)).toLowerCase();
        if (context.includes('gmbh') || context.includes('ag ') || context.includes('kg ') ||
            context.includes('company') || context.includes('firma')) {
          return;
        }
      }

      if (type === 'creditCard') {
        // Validate credit card using Luhn algorithm to reduce false positives
        const digits = originalValue.replace(/[\s-]/g, '');
        if (!luhnCheck(digits)) {
          return;
        }
      }

      const maskedValue = maskingFunctions[type](originalValue);
      const originalHash = hashValue(originalValue);

      // Encrypt the original value using AES-256-GCM
      const encryptedData = encryptValue(originalValue, encryptionKeyId);

      // Get PII category
      const piiCategory = categorizePII(type);
      piiCategoriesDetected.add(piiCategory);

      // Replace in text
      text = text.replace(originalValue, maskedValue);

      // Mark positions as masked
      for (let i = position; i < position + originalValue.length; i++) {
        maskedPositions.add(i);
      }

      // Record masking operation in masking_map with encrypted data
      maskingMap.push({
        id: generateId(),
        type: type,
        pii_category: piiCategory,
        masked_value: maskedValue,
        encrypted_value: encryptedData.encrypted,
        encryption_iv: encryptedData.iv,
        encryption_auth_tag: encryptedData.authTag,
        encryption_key_id: encryptedData.keyId,
        original_hash: originalHash,
        position: position,
        timestamp: new Date().toISOString()
      });

      maskedCount++;
    });
  }

  // Verify GDPR compliance - all PII types must be properly masked and encrypted
  const allPIIMasked = maskedCount > 0;
  const allPIIEncrypted = maskingMap.every(entry => entry.encrypted_value && entry.encryption_key_id);
  const gdprCompliant = allPIIMasked && allPIIEncrypted;

  return {
    json: {
      text: text,
      masking_map: maskingMap,
      audit_log: {
        masked_count: maskedCount,
        processed_at: new Date().toISOString(),
        encryption_method: 'AES-256-GCM',
        data_minimization_applied: true,
        gdpr_compliant: gdprCompliant,
        pii_types_detected: [...new Set(maskingMap.map(m => m.type))],
        pii_categories_detected: [...piiCategoriesDetected],
        total_pii_instances: maskedCount,
        encryption_key_id: encryptionKeyId
      }
    }
  };
});

// Helper function for Luhn algorithm (credit card validation)
function luhnCheck(cardNumber) {
  let sum = 0;
  let isEven = false;

  for (let i = cardNumber.length - 1; i >= 0; i--) {
    let digit = parseInt(cardNumber[i], 10);

    if (isEven) {
      digit *= 2;
      if (digit > 9) {
        digit -= 9;
      }
    }

    sum += digit;
    isEven = !isEven;
  }

  return sum % 10 === 0;
}

// Schedule data deletion based on retention policy
const config = $('Workflow Configuration').first().json;
const dataRetentionDays = config.dataRetentionDays || 30;

// Calculate deletion timestamp
const now = new Date();
const deletionDate = new Date(now.getTime() + (dataRetentionDays * 24 * 60 * 60 * 1000));

return items.map(item => {
  return {
    json: {
      ...item.json,
      deletion_scheduled_at: deletionDate.toISOString(),
      automated_deletion_scheduled: true,
      data_subject_notification: false,
      gdpr_compliance: {
        right_to_erasure: true,
        data_minimization_applied: true,
        purpose_limitation_documented: true,
        retention_period_days: dataRetentionDays,
        scheduled_deletion_date: deletionDate.toISOString().split('T')[0],
        storage_limitation_compliance: true,
        lawfulness_of_processing: 'consent',
        purpose_limitation: 'document_processing_only'
      }
    }
  };
});

// Validate Input & Check Consent
const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const ALLOWED_FILE_TYPES = [
  'application/pdf',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/vnd.ms-excel',
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'image/jpeg',
  'image/png',
  'image/tiff',
  'image/jpg',
  'image/bmp'
];

const item = $input.first();
const body = item.json.body || {};
const binary = item.binary || {};

// Check for user consent flag
if (!body.gdprConsent || body.gdprConsent !== true) {
  throw new Error('GDPR consent is required. User must explicitly consent to data processing.');
}

// Verify GDPR consent timestamp is present
if (!body.consentTimestamp) {
  throw new Error('GDPR consent timestamp is missing. Cannot proceed without valid consent record.');
}

// Validate consent timestamp format (ISO 8601)
const consentDate = new Date(body.consentTimestamp);
if (isNaN(consentDate.getTime())) {
  throw new Error('Invalid consent timestamp format. Expected ISO 8601 format.');
}

// Check if file is present
const firstBinaryKey = Object.keys(binary)[0];
if (!firstBinaryKey) {
  throw new Error('No file uploaded. Please provide a document to process.');
}

const file = binary[firstBinaryKey];

// Validate file size
if (file.fileSize && file.fileSize > MAX_FILE_SIZE) {
  throw new Error(`File size exceeds maximum allowed size of ${MAX_FILE_SIZE / 1024 / 1024}MB. Current size: ${(file.fileSize / 1024 / 1024).toFixed(2)}MB`);
}

// Validate file type
if (!ALLOWED_FILE_TYPES.includes(file.mimeType)) {
  throw new Error(`File type '${file.mimeType}' is not allowed. Allowed types: ${ALLOWED_FILE_TYPES.join(', ')}`);
}

// All validations passed - return item with consent metadata
return [{
  json: {
    ...item.json,
    validationPassed: true,
    consentVerified: true,
    consentTimestamp: body.consentTimestamp,
    fileValidated: true,
    fileName: file.fileName,
    fileSize: file.fileSize,
    mimeType: file.mimeType
  },
  binary: binary
}];

// Format comprehensive error details from failed extraction steps
// Enhanced with retry tracking - only proceed to email notification after 2 failures
const items = $input.all();

// Collect all error information
const errorDetails = items.map((item, index) => {
  const error = item.json.error || {};
  const errorMessage = error.message || item.json.errorMessage || 'Unknown error occurred';
  const errorStack = error.stack || item.json.errorStack || '';

  // Get retry count from previous attempts (stored in item data)
  const currentRetryCount = item.json.retry_count || 0;
  const maxRetries = 2;

  // Determine if this should be retried or if it's a final failure
  const shouldRetry = currentRetryCount < maxRetries;
  const isFinalFailure = currentRetryCount >= maxRetries;

  // Determine which node/stage failed
  let failedNode = 'Unknown';
  let processingStage = 'Unknown';

  // Try to extract node information from error or item metadata
  if (item.json.node) {
    failedNode = item.json.node;
  } else if (errorStack.includes('Mistral')) {
    failedNode = 'Mistral DOC OCR1';
    processingStage = 'OCR Processing';
  } else if (errorStack.includes('HTTP Request')) {
    failedNode = 'HTTP Request3';
    processingStage = 'Text Extraction';
  } else if (errorStack.includes('Extract from File')) {
    failedNode = 'Extract from File2';
    processingStage = 'PDF Extraction';
  } else if (errorStack.includes('AI Agent')) {
    failedNode = 'AI Agent5';
    processingStage = 'AI Parsing';
  } else if (errorStack.includes('Code')) {
    failedNode = 'Code Node';
    processingStage = 'Data Processing';
  }

  // Get file information from earlier nodes
  const fileInfo = {
    fileName: item.json.fileName || item.json.file_name || 'Unknown',
    fileSize: item.json.fileSize || item.json.file_size || 0,
    mimeType: item.json.mimeType || item.json.mime_type || 'Unknown'
  };

  return {
    error_id: `error_${$execution.id}_${index}`,
    execution_id: $execution.id,
    workflow_id: $workflow.id,
    timestamp: new Date().toISOString(),
    failed_node: failedNode,
    processing_stage: processingStage,
    error_message: errorMessage,
    error_stack: errorStack,
    file_name: fileInfo.fileName,
    file_size: fileInfo.fileSize,
    mime_type: fileInfo.mimeType,
    user_id: item.json.user_id || null,
    ip_address: item.json.ip_address || 'Unknown',
    retry_count: currentRetryCount,
    should_retry: shouldRetry,
    is_final_failure: isFinalFailure,
    max_retries: maxRetries,
    retry_status: shouldRetry ? `Retriable (attempt ${currentRetryCount + 1}/${maxRetries})` : `Final failure after ${currentRetryCount} attempts`,
    proceed_to_notification: isFinalFailure,
    is_recoverable: !errorMessage.toLowerCase().includes('fatal') && !errorMessage.toLowerCase().includes('invalid file'),
    error_category: categorizeError(errorMessage)
  };
});

// Helper function to categorize errors
function categorizeError(message) {
  const msg = message.toLowerCase();
  if (msg.includes('timeout') || msg.includes('network')) return 'network_error';
  if (msg.includes('parse') || msg.includes('json')) return 'parsing_error';
  if (msg.includes('file') || msg.includes('format')) return 'file_error';
  if (msg.includes('auth') || msg.includes('credential')) return 'authentication_error';
  if (msg.includes('rate limit') || msg.includes('quota')) return 'rate_limit_error';
  return 'general_error';
}

// Return formatted error details
return errorDetails.map(detail => ({ json: detail }));

// Log Excel extraction error with comprehensive details
const items = $input.all();

return items.map(item => {
  const error = item.json.error || {};
  const errorMessage = error.message || item.json.errorMessage || 'Excel extraction failed';
  const errorStack = error.stack || item.json.errorStack || '';

  // Get file information from earlier nodes
  const fileInfo = {
    fileName: item.json.fileName || item.json.file_name || 'Unknown',
    fileSize: item.json.fileSize || item.json.file_size || 0,
    mimeType: item.json.mimeType || item.json.mime_type || 'Unknown'
  };

  return {
    json: {
      error_id: `excel_error_${$execution.id}`,
      execution_id: $execution.id,
      workflow_id: $workflow.id,
      timestamp: new Date().toISOString(),
      failed_node: 'Edit Fields7',
      processing_stage: 'Excel Extraction',
      error_message: errorMessage,
      error_stack: errorStack,
      file_name: fileInfo.fileName,
      file_size: fileInfo.fileSize,
      mime_type: fileInfo.mimeType,
      user_id: item.json.user_id || null,
      ip_address: item.json.ip_address || 'Unknown',
      error_category: 'excel_extraction_error'
    }
  };
});

// Log PDF extraction error with comprehensive details
