// Restore Unmasked Data - Selective restoration of brand names while preserving ALL PII
// Enhanced with AES-256 decryption support for encrypted original_value fields
const crypto = require('crypto');
const items = $input.all();
const firstItem = items[0];

// 1. Retrieve masking_map from Enhanced Masking node
const maskingData = $('Enhanced Masking with Audit').first().json;
const maskingMap = maskingData.masking_map || [];

// 2. Get AI-processed JSON output from current input (Code9 output)
let processedData = firstItem.json;

// 3. Convert the JSON output to string for text replacement
let dataString = JSON.stringify(processedData, null, 2);

// Define PII categories for GDPR compliance reporting
const piiCategories = {
  personal_identifiers: ['ssn', 'passport', 'id_card', 'tax_id', 'vat_id', 'dob'],
  financial_data: ['iban', 'credit_card', 'bank_account'],
  contact_info: ['email', 'phone', 'fax'],
  location_data: ['postal_code', 'street_address', 'ip_address']
};

// Track restoration operations for audit
const restorationAudit = {
  timestamp: new Date().toISOString(),
  total_masked_fields: maskingMap.length,
  restored_count: 0,
  kept_masked_count: 0,
  restored_fields: [],
  kept_masked_fields: [],
  decryption_failures: []
};

// Initialize GDPR compliance tracking by category
const gdprCompliance = {
  pii_kept_masked: true,
  brand_names_restored: false,
  restoration_timestamp: new Date().toISOString(),
  encryption_verified: true,
  protected_pii_categories: {
    personal_identifiers: { count: 0, types: [] },
    financial_data: { count: 0, types: [] },
    contact_info: { count: 0, types: [] },
    location_data: { count: 0, types: [] },
    company_protection: { count: 0, types: [] }
  },
  total_pii_protected: 0,
  data_subject_rights: {
    right_to_access: true,
    right_to_rectification: true,
    right_to_erasure: true,
    right_to_data_portability: true,
    right_to_object: true
  }
};

// Helper function to decrypt AES-256 encrypted data
function decryptAES256(encryptedData, encryptionKeyId) {
  try {
    // Parse encrypted data (format: iv:encryptedText:authTag)
    const parts = encryptedData.split(':');
    if (parts.length !== 3) {
      throw new Error('Invalid encrypted data format');
    }

    const iv = Buffer.from(parts[0], 'hex');
    const encryptedText = Buffer.from(parts[1], 'hex');
    const authTag = Buffer.from(parts[2], 'hex');

    // Retrieve encryption key from environment or secure storage
    // In production, this should fetch from a secure key management service
    const encryptionKey = process.env[`ENCRYPTION_KEY_${encryptionKeyId}`] || process.env.ENCRYPTION_KEY;

    if (!encryptionKey) {
      throw new Error(`Encryption key not found for key_id: ${encryptionKeyId}`);
    }

    // Create decipher
    const decipher = crypto.createDecipheriv('aes-256-gcm', Buffer.from(encryptionKey, 'hex'), iv);
    decipher.setAuthTag(authTag);

    // Decrypt
    let decrypted = decipher.update(encryptedText, null, 'utf8');
    decrypted += decipher.final('utf8');

    return { success: true, data: decrypted };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

// Helper function to categorize PII type
function categorizePII(type) {
  for (const [category, types] of Object.entries(piiCategories)) {
    if (types.includes(type)) {
      return category;
    }
  }
  if (type === 'nosta') {
    return 'company_protection';
  }
  return 'other';
}

// 4. Iterate through masking_map entries
maskingMap.forEach(entry => {
  const { type, masked_value, original_value, original_hash, encryption_key_id, is_encrypted } = entry;

  // 5. For type='companyLegalForm' entries: restore original_value (brand names)
  if (type === 'companyLegalForm') {
    let valueToRestore = original_value;
    let decryptionSuccess = true;

    // Check if original_value is encrypted
    if (is_encrypted === true && encryption_key_id) {
      const decryptResult = decryptAES256(original_value, encryption_key_id);

      if (decryptResult.success) {
        valueToRestore = decryptResult.data;
      } else {
        // Decryption failed - keep masked and log failure
        decryptionSuccess = false;
        gdprCompliance.encryption_verified = false;

        restorationAudit.decryption_failures.push({
          type: type,
          masked_value: masked_value,
          encryption_key_id: encryption_key_id,
          error: decryptResult.error,
          timestamp: new Date().toISOString()
        });

        restorationAudit.kept_masked_count++;
        restorationAudit.kept_masked_fields.push({
          type: type,
          masked_value: masked_value,
          reason: `Decryption failed: ${decryptResult.error}`,
          pii_category: 'company_protection'
        });

        return; // Skip restoration for this entry
      }
    }

    // Replace masked value with decrypted/original value
    const regex = new RegExp(masked_value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
    dataString = dataString.replace(regex, valueToRestore);

    restorationAudit.restored_count++;
    restorationAudit.restored_fields.push({
      type: type,
      masked_value: masked_value,
      restored_to: valueToRestore,
      hash: original_hash,
      was_encrypted: is_encrypted === true,
      decryption_success: decryptionSuccess
    });

    gdprCompliance.brand_names_restored = true;
  }
  // 6. For type='nosta' entries: keep masked as '[FILTERED_COMPANY]' - do NOT restore
  else if (type === 'nosta') {
    const category = 'company_protection';
    restorationAudit.kept_masked_count++;
    restorationAudit.kept_masked_fields.push({
      type: type,
      masked_value: masked_value,
      reason: 'Company name protection - kept masked',
      pii_category: category
    });

    gdprCompliance.protected_pii_categories[category].count++;
    if (!gdprCompliance.protected_pii_categories[category].types.includes(type)) {
      gdprCompliance.protected_pii_categories[category].types.push(type);
    }
    gdprCompliance.total_pii_protected++;
  }
  // 7. For ALL PII types: keep masked - do NOT restore (PII protection)
  else if (['email', 'phone', 'fax', 'postal_code', 'tax_id', 'vat_id', 'iban', 
             'ssn', 'passport', 'id_card', 'ip_address', 'street_address', 'dob'].includes(type)) {
    const category = categorizePII(type);
    restorationAudit.kept_masked_count++;
    restorationAudit.kept_masked_fields.push({
      type: type,
      masked_value: masked_value,
      reason: 'PII protection - kept masked',
      pii_category: category
    });

    if (category !== 'other') {
      gdprCompliance.protected_pii_categories[category].count++;
      if (!gdprCompliance.protected_pii_categories[category].types.includes(type)) {
        gdprCompliance.protected_pii_categories[category].types.push(type);
      }
      gdprCompliance.total_pii_protected++;
    }
  }
});

// 8. Parse the restored string back to JSON
let restoredData;
try {
  restoredData = JSON.parse(dataString);
} catch (error) {
  // If parsing fails, return original data with error info
  return [{
    json: {
      ...processedData,
      restoration_error: 'Failed to parse restored data',
      restoration_audit: restorationAudit,
      gdpr_compliance: gdprCompliance
    }
  }];
}

// 9. Return output with restored brand names but preserved ALL PII masking
// 10. Include restoration_audit field tracking what was restored vs kept masked
// 11. Include detailed GDPR compliance breakdown by PII category
// 12. Include encryption verification status and data subject rights
return [{
  json: {
    ...restoredData,
    restoration_audit: restorationAudit,
    gdpr_compliance: gdprCompliance
  }
}];

// Track Retry Count - Preserve all fields including binary data
const items = $input.all();

return items.map(item => {
  // Get current retry count from error data or initialize to 0
  const currentRetryCount = item.json.retry_count || 0;

  // Preserve all existing JSON fields
  const preservedJson = { ...item.json };

  // Update retry count
  preservedJson.retry_count = currentRetryCount;

  // Preserve binary data if it exists
  const preservedBinary = item.binary ? { ...item.binary } : undefined;

  return {
    json: preservedJson,
    binary: preservedBinary
  };
});

// Increment retry counter and preserve all data including binary
const items = $input.all();

return items.map(item => {
  const currentRetryCount = item.json.retry_count || 0;
  const newRetryCount = currentRetryCount + 1;

  return {
    json: {
      ...item.json,
      retry_count: newRetryCount,
      retry_timestamp: new Date().toISOString(),
      retry_attempt: `Attempt ${newRetryCount} of 2`
    },
    binary: item.binary || {}
  };
});
